// Chart memory management — destroy charts of inactive tabs
var _currentTab = 'tab-dash';
function _destroyTabCharts(tabId) {
  if (tabId === 'tab-dash') {
    if (chartPerf && typeof chartPerf.destroy === 'function') { chartPerf.destroy(); chartPerf = null; }
    if (window.chartPerfLine && typeof window.chartPerfLine.destroy === 'function') { window.chartPerfLine.destroy(); window.chartPerfLine = null; }
    if (window._chartPerfLine && typeof window._chartPerfLine.destroy === 'function') { window._chartPerfLine.destroy(); window._chartPerfLine = null; }
    if (chartSBD && typeof chartSBD.destroy === 'function') { chartSBD.destroy(); chartSBD = null; }
    if (chartVolume && typeof chartVolume.destroy === 'function') { chartVolume.destroy(); chartVolume = null; }
  }
  if (tabId === 'tab-stats') {
    if (chartMuscleEvol && typeof chartMuscleEvol.destroy === 'function') { chartMuscleEvol.destroy(); chartMuscleEvol = null; }
  }
}

// Routine active : perso (db.routine) > généré (db.generatedProgram) > template > rien
function getRoutine() {
  // Priorité 1 : routine personnalisée (modifiée dans Réglages > Mon Programme)
  if (db.routine && Object.keys(db.routine).length > 0) return db.routine;
  // Priorité 2 : routine générée à l'onboarding
  if (db.generatedProgram && db.generatedProgram.length > 0) {
    const r = {};
    db.generatedProgram.forEach(d => { r[d.day] = d.isRest ? '😴 Repos' : (d.label || d.day); });
    return r;
  }
  // Priorité 3 : template par défaut selon le mode
  const style = modeFeature('programStyle');
  if (style && ROUTINE_TEMPLATES[style]) return ROUTINE_TEMPLATES[style].routine;
  return DEFAULT_ROUTINE;
}

var _saveDBTimer = null;
var _saveDBDirty = false;

function saveDB() {
  clearCaches();
  _saveDBDirty = true;
  if (_saveDBTimer) return; // already scheduled
  _saveDBTimer = setTimeout(function() {
    _saveDBTimer = null;
    _flushDB();
  }, 2000);
  debouncedCloudSync();
}

function saveDBNow() {
  clearCaches();
  if (_saveDBTimer) { clearTimeout(_saveDBTimer); _saveDBTimer = null; }
  _saveDBDirty = true;
  _flushDB();
  debouncedCloudSync();
}

function _flushDB() {
  if (!_saveDBDirty) return;
  _saveDBDirty = false;
  try {
    if (!db.gamification) db.gamification = {};
    db.updatedAt = Date.now();
    localStorage.setItem(STORAGE_KEY, JSON.stringify(db));
  } catch(e) {
    console.error('saveDB error:', e);
    // Surface quota errors to the user instead of failing silently — otherwise
    // users keep training and the data quietly stops persisting.
    var isQuota = e && (e.name === 'QuotaExceededError' || e.code === 22 || /quota/i.test(e.message || ''));
    if (isQuota && typeof showToast === 'function') {
      showToast('⚠️ Stockage local plein — synchronise avec le cloud');
    }
  }
}

// Flush before leaving/hiding the page
window.addEventListener('beforeunload', _flushDB);
document.addEventListener('visibilitychange', function() {
  if (document.visibilityState === 'hidden') _flushDB();
});

// Global error trap — capture "n is not a function" et autres TypeError
// minifiés pour que l'app ne plante pas silencieusement chez l'utilisateur.
window.addEventListener('error', function(event) {
  if (!event || !event.error) return;
  var msg = String(event.error.message || event.message || 'Unknown error');
  // Ignorer les erreurs réseau/Supabase déjà gérées ailleurs
  if (/Failed to fetch|NetworkError|Load failed|ResizeObserver/i.test(msg)) return;
  try {
    if (typeof logErrorToSupabase === 'function') {
      logErrorToSupabase('window_error', msg.substring(0, 500),
        (event.filename || '?') + ':' + (event.lineno || '?'));
    }
  } catch(e) {}
});
window.addEventListener('unhandledrejection', function(event) {
  if (!event || !event.reason) return;
  var msg = String(event.reason.message || event.reason || 'Unhandled rejection');
  if (/Failed to fetch|NetworkError|Load failed|AbortError/i.test(msg)) return;
  try {
    if (typeof logErrorToSupabase === 'function') {
      logErrorToSupabase('unhandled_rejection', msg.substring(0, 500), 'promise');
    }
  } catch(e) {}
});
function debouncedCloudSync() {
  if (!cloudSyncEnabled) return;
  if (!navigator.onLine) {
    db.pendingSync = true;
    _flushDB();
    return;
  }
  clearTimeout(syncDebounceTimer);
  syncDebounceTimer = setTimeout(() => { syncToCloud(true); }, 2000);
}

window.addEventListener('online', function() {
  if (db.pendingSync && cloudSyncEnabled) {
    db.pendingSync = false;
    _flushDB();
    if (typeof syncToCloud === 'function') syncToCloud(true);
    if (typeof showToast === 'function') showToast('📶 Connexion rétablie — séance synchronisée');
  }
});
function generateId() { return Math.random().toString(36).substr(2, 9); }

// ── GAMIFICATION — defensive init ───────────────────────────
db.gamification = db.gamification || {};
db.gamification.streakFreezes = db.gamification.streakFreezes ?? 1;
db.gamification.lastFreezeGrantedMonth = db.gamification.lastFreezeGrantedMonth ?? -1;
db.gamification.freezesUsedAt = db.gamification.freezesUsedAt ?? [];
db.gamification.freezeActiveThisWeek = db.gamification.freezeActiveThisWeek ?? false;
db.gamification.freezeProtectedWeeks = db.gamification.freezeProtectedWeeks ?? [];

// One-time migration V2 : l'ancien calcStreak consommait un freeze par appel
// pour le MÊME trou (pas de suivi des semaines protégées). Reset propre.
if (!db.gamification._migratedFreezeV2) {
  db.gamification.streakFreezes = 2;
  db.gamification.freezesUsedAt = [];
  db.gamification._migratedFreezeV2 = true;
}

// One-time migration V3 : les clés stockées avant étaient des dates "YYYY-MM-DD"
// (Monday UTC), décalées d'un jour selon timezone/DST. Nouvelles clés ISO
// "YYYY-Www" cohérentes en UTC. On vide freezeProtectedWeeks (stale) et on
// restaure 2 freezes pour laisser calcStreak re-bridger sur les vrais trous.
if (!db.gamification._migratedFreezeV3) {
  db.gamification.streakFreezes = 2;
  db.gamification.freezesUsedAt = [];
  db.gamification.freezeProtectedWeeks = [];
  db.gamification._migratedFreezeV3 = true;
}
// One-time migration V4 : les freezes ne sont plus rétroactifs avant 2026.
// On vide les semaines protégées (potentiellement pré-2026) et on restaure 2 freezes.
if (!db.gamification._migratedFreezeV4) {
  db.gamification.streakFreezes = 2;
  db.gamification.freezesUsedAt = [];
  db.gamification.freezeProtectedWeeks = [];
  db.gamification._migratedFreezeV4 = true;
}

