if (db._leaderboardMetric === undefined) db._leaderboardMetric = 'dots';

// ── db.routine rebuild from weeklyPlan if empty (v162) ───────
if ((!db.routine || !Object.keys(db.routine).length) && db.weeklyPlan && db.weeklyPlan.days) {
  db.routine = {};
  db.weeklyPlan.days.forEach(function(d) {
    if (!d.rest && d.day && d.title) db.routine[d.day] = d.title;
  });
}

// ── db.routine all-Repos guard (v164) ────────────────────────
// 504/409 conflict during sync can overwrite routine with all '😴 Repos'.
// If weeklyPlan still has real exercises, rebuild routine from it.
(function() {
  var _rv = db.routine ? Object.values(db.routine) : [];
  var _allRest = _rv.length > 0 && _rv.every(function(v) { return !v || /repos/i.test(v); });
  var _hasReal = db.weeklyPlan && db.weeklyPlan.days && db.weeklyPlan.days.some(function(d) {
    return !d.rest && d.exercises && d.exercises.length > 0;
  });
  if (_allRest && _hasReal) {
    db.weeklyPlan.days.forEach(function(d) {
      if (!d.rest && d.day && d.title) db.routine[d.day] = d.title;
    });
  }
}());

// ── WEB PUSH — v160 ──────────────────────────────────────────
if (!db.notificationHistory) db.notificationHistory = [];
if (db._unreadNotifications === undefined) db._unreadNotifications = 0;
if (db._lastPushSent === undefined) db._lastPushSent = null;
if (db._pushEnabled === undefined) db._pushEnabled = false;
if (db._lastPushAcwr === undefined) db._lastPushAcwr = 0;
if (db._lastPushStreak === undefined) db._lastPushStreak = 0;

// One-shot fix: stale 'Jour X' labels in db.routine overwritten by cloud sync.
// Replace with the canonical exercise name from the matching weeklyPlan day.
if (!db._routineFixed) {
  var stalePattern = /^(🔄\s*)?Jour\s*\d+$/i;
  var routine = db.routine || {};
  Object.keys(routine).forEach(function(day) {
    if (stalePattern.test(routine[day])) {
      var wpDay = (db.weeklyPlan && db.weeklyPlan.days || [])
        .find(function(d) { return d.day === day; });
      var primaryExo = wpDay && (wpDay.exercises || [])
        .find(function(e) { return e.isPrimary; });
      if (primaryExo) {
        routine[day] = primaryExo.name;
      }
    }
  });
  db.routine = routine;
  db._routineFixed = true;
  saveDB();
}

db.gamification.playerClass = db.gamification.playerClass ?? null;
db.gamification.quizAnswers = db.gamification.quizAnswers ?? [];
db.gamification.quizCompletedAt = db.gamification.quizCompletedAt ?? null;
db.gamification.liftRanks = db.gamification.liftRanks || null;
db.gamification.muscleRanks = db.gamification.muscleRanks || null;
db.gamification.lastTab = db.gamification.lastTab || {
  main: 'tab-dash',
  jeux: 'jeux-profil-joueur',
  seances: 's-go',
  social: 'feed-amis',
  profil: 'tab-corps'
};

// Update lastTab state + persist to localStorage + debounced cloud sync
function _updateLastTab(key, value) {
  if (!db.gamification) db.gamification = {};
  if (!db.gamification.lastTab) db.gamification.lastTab = {};
  db.gamification.lastTab[key] = value;
  try { localStorage.setItem('sbd_lastTab', JSON.stringify(db.gamification.lastTab)); } catch(e) {}
  if (typeof debouncedCloudSync === 'function') debouncedCloudSync();
}

// ── READINESS PRÉ-SÉANCE ────────────────────────────────────
db.readiness = db.readiness || [];

function getTodayStr() { return new Date().toISOString().slice(0, 10); }

function hasTodayReadiness() {
  const today = getTodayStr();
  return (db.readiness || []).some(r => r.date === today);
}

function isTodayTrainingDay() {
  const routine = getRoutine();
  const todayName = DAYS_FULL[new Date().getDay()];
  const label = routine[todayName] || '';
  return label && !/repos|😴/i.test(label);
}

function getTodayReadiness() {
  const today = getTodayStr();
  return (db.readiness || []).find(r => r.date === today) || null;
}

function showReadinessModal(onComplete) {
  if (hasTodayReadiness()) { if (onComplete) onComplete(); return; }
  _readinessOnComplete = onComplete || null;
  const overlay = document.createElement('div');
  overlay.className = 'modal-overlay';
  overlay.id = 'readinessModal';
  overlay.innerHTML = `<div class="modal-box" style="max-width:360px;padding:16px;">
    <div style="font-size:15px;font-weight:700;margin-bottom:10px;text-align:center;">Comment te sens-tu ?</div>
    <div class="readiness-sliders" style="margin-bottom:8px;">
      <div class="readiness-row" style="margin-bottom:6px;"><span style="font-size:12px;">😴 Sommeil</span><input type="range" min="1" max="10" value="5" id="rd-sleep"><span id="rd-sleep-val" style="font-size:12px;min-width:16px;">5</span></div>
      <div class="readiness-row" style="margin-bottom:6px;"><span style="font-size:12px;">⚡ Énergie</span><input type="range" min="1" max="10" value="5" id="rd-energy"><span id="rd-energy-val" style="font-size:12px;min-width:16px;">5</span></div>
      <div class="readiness-row" style="margin-bottom:6px;"><span style="font-size:12px;">🧠 Motivation</span><input type="range" min="1" max="10" value="5" id="rd-motivation"><span id="rd-motivation-val" style="font-size:12px;min-width:16px;">5</span></div>
      <div class="readiness-row" style="margin-bottom:4px;"><span style="font-size:12px;">🦵 Courbatures</span><input type="range" min="1" max="10" value="5" id="rd-soreness"><span id="rd-soreness-val" style="font-size:12px;min-width:16px;">5</span></div>
    </div>
    <div style="font-size:9px;color:var(--sub);text-align:center;margin:2px 0 6px;">1 = mauvais · 10 = excellent (courbatures : 10 = très courbaturé)</div>
    <div id="rd-score-preview" style="text-align:center;font-size:13px;font-weight:700;margin:6px 0 2px;color:var(--blue);">Score : —</div>
    <div id="rd-adj-preview" style="text-align:center;font-size:11px;color:var(--sub);margin-bottom:10px;"></div>
    <div class="modal-actions" style="margin-top:10px;">
      <button class="modal-cancel" style="background:var(--sub);color:#000;" onclick="skipReadiness()">Passer</button>
      <button class="modal-confirm" style="background:var(--green);color:#000;" onclick="submitReadiness()">Valider ✓</button>
    </div>
  </div>`;
  document.body.appendChild(overlay);
  ['sleep','energy','motivation','soreness'].forEach(k => {
    const slider = document.getElementById('rd-'+k);
    slider.oninput = () => {
      document.getElementById('rd-'+k+'-val').textContent = slider.value;
      updateReadinessPreview();
    };
  });
  updateReadinessPreview();
}

// ── DOMS Modal — évaluation courbatures avant séance GO ──────────────────
// Affiché après la Readiness Modal, avant _goDoStartWorkout()
// Ne montre que les muscles ciblés par la séance du jour
function showDOMSModal(callback) {
  // Déjà renseigné aujourd'hui ?
  var todayDOMS = typeof getTodayDOMS === 'function' ? getTodayDOMS() : {};
  if (Object.keys(todayDOMS).length > 0) { if (callback) callback(); return; }

  // Muscles ciblés par la séance du jour
  var todayDay = DAYS_FULL[new Date().getDay()];
  var dayExos = typeof getProgExosForDay === 'function' ? getProgExosForDay(todayDay) : [];
  var musclesSet = {};
  dayExos.forEach(function(exoRef) {
    var contribs = typeof getMuscleContributions === 'function'
      ? getMuscleContributions(exoRef) : [];
    contribs.forEach(function(mc) {
      var key = typeof getMuscleKey === 'function' ? getMuscleKey(mc.muscle) : null;
      if (key && mc.coeff >= 0.5) musclesSet[key] = true;
    });
  });
  var muscles = Object.keys(musclesSet);
  if (muscles.length === 0) { if (callback) callback(); return; }

  var MUSCLE_LABELS = {
    quads: 'Quadriceps', ischio: 'Ischios', fessiers: 'Fessiers',
    dos: 'Dos', pecs: 'Pectoraux', epaules: 'Épaules',
    biceps: 'Biceps', triceps: 'Triceps', mollets: 'Mollets',
    abdos: 'Abdos', trapezes: 'Trapèzes', avant_bras: 'Avant-bras'
  };

  window._domsValues = {};
  muscles.forEach(function(m) { window._domsValues[m] = 0; });

  var html = '<div style="padding:16px;">';
  html += '<div style="font-size:15px;font-weight:700;margin-bottom:4px;">💪 Courbatures du jour</div>';
  html += '<div style="font-size:12px;color:var(--sub);margin-bottom:16px;">Comment vont ces muscles ? (0 = aucune, 5 = très douloureux)</div>';
  muscles.forEach(function(muscle) {
    var label = MUSCLE_LABELS[muscle] || muscle;
    html += '<div style="margin-bottom:12px;">';
    html += '<div style="font-size:12px;font-weight:600;color:var(--text);margin-bottom:6px;">' + label + '</div>';
    html += '<div style="display:flex;gap:6px;">';
    [0,1,2,3,4,5].forEach(function(score) {
      var emoji = score === 0 ? '✅' : score <= 2 ? '🟡' : score <= 3 ? '🟠' : '🔴';
      html += '<button class="doms-btn" data-muscle="' + muscle + '" data-score="' + score + '" ' +
        'onclick="domsSetScore(\'' + muscle + '\',' + score + ',this)" ' +
        'style="flex:1;padding:6px 2px;border-radius:8px;border:1.5px solid var(--border);' +
        'background:var(--surface);font-size:13px;cursor:pointer;">' +
        emoji + '<br><span style="font-size:10px;color:var(--sub);">' + score + '</span></button>';
    });
    html += '</div></div>';
  });
  html += '<button onclick="domsConfirm()" style="width:100%;padding:12px;margin-top:8px;' +
    'background:var(--accent);border:none;border-radius:12px;color:#000;font-weight:700;' +
    'font-size:14px;cursor:pointer;">Continuer →</button>';
  html += '<button onclick="domsSkip()" style="width:100%;padding:8px;margin-top:6px;' +
    'background:transparent;border:none;color:var(--sub);font-size:12px;cursor:pointer;">Passer</button>';
  html += '</div>';

  var overlay = document.createElement('div');
  overlay.id = 'doms-modal-overlay';
  overlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;' +
    'background:rgba(0,0,0,0.7);display:flex;align-items:flex-end;justify-content:center;z-index:9999;';
  overlay.innerHTML = '<div style="background:var(--card);border-radius:20px 20px 0 0;' +
    'width:100%;max-width:500px;max-height:80vh;overflow-y:auto;">' + html + '</div>';
  document.body.appendChild(overlay);
  window._domsCallback = callback;
}

window.domsSetScore = function(muscle, score, btn) {
  if (!window._domsValues) return;
  window._domsValues[muscle] = score;
  var parent = btn.closest('div[style*="display:flex"]');
  if (parent) parent.querySelectorAll('.doms-btn').forEach(function(b) {
    b.style.borderColor = 'var(--border)'; b.style.background = 'var(--surface)';
  });
  btn.style.borderColor = 'var(--accent)';
  btn.style.background = 'rgba(10,132,255,0.15)';
};

window.domsConfirm = function() {
  if (typeof saveTodayDOMS === 'function') saveTodayDOMS(window._domsValues || {});
  var overlay = document.getElementById('doms-modal-overlay');
  if (overlay) overlay.remove();
  var cb = window._domsCallback; window._domsCallback = null;
  if (cb) cb();
};

window.domsSkip = function() {
  var overlay = document.getElementById('doms-modal-overlay');
  if (overlay) overlay.remove();
  var cb = window._domsCallback; window._domsCallback = null;
  if (cb) cb();
};

function updateReadinessPreview() {
  const sleep = parseInt(document.getElementById('rd-sleep')?.value || 5);
  const energy = parseInt(document.getElementById('rd-energy')?.value || 5);
  const motivation = parseInt(document.getElementById('rd-motivation')?.value || 5);
  const soreness = parseInt(document.getElementById('rd-soreness')?.value || 5);
  const score = calculateReadiness(sleep, energy, motivation, soreness);
  const adj = getReadinessLoadAdjustment(score);
  const pctStr = adj >= 1 ? '+' + Math.round((adj - 1) * 100) + '%' : Math.round((adj - 1) * 100) + '%';
  const el = document.getElementById('rd-score-preview');
  const adjEl = document.getElementById('rd-adj-preview');
  if (el) el.textContent = 'Score readiness : ' + score + '%';
  if (el) el.style.color = score >= 80 ? 'var(--green)' : score >= 60 ? 'var(--blue)' : 'var(--orange)';
  if (adjEl) adjEl.textContent = adj === 1 ? 'Charges inchangées' : 'Charges ajustées : ' + pctStr;
}

// Calcul readiness pondéré (Helms 2018, Zourdos 2016)
function calculateReadiness(sleep, energy, motivation, soreness) {
  const sorenessInverted = 11 - soreness;
  return Math.min(100, Math.max(0, Math.round(
    (sleep * 0.35 + energy * 0.25 + motivation * 0.15 + sorenessInverted * 0.25) * 10
  )));
}

// Ajustement charge selon readiness (Tuchscherer RPE system, Helms 2018)
function getReadinessLoadAdjustment(readinessScore) {
  if (readinessScore >= 90) return 1.03;
  if (readinessScore >= 80) return 1.00;
  if (readinessScore >= 70) return 0.97;
  if (readinessScore >= 60) return 0.93;
  if (readinessScore >= 50) return 0.90;
  if (readinessScore >= 40) return 0.85;
  return 0.80;
}

let _readinessOnComplete = null;

function skipReadiness() {
  const modal = document.getElementById('readinessModal');
  if (modal) modal.remove();
  if (_readinessOnComplete) { _readinessOnComplete(); _readinessOnComplete = null; }
}

function submitReadiness() {
  const sleep = parseInt(document.getElementById('rd-sleep').value);
  const energy = parseInt(document.getElementById('rd-energy').value);
  const motivation = parseInt(document.getElementById('rd-motivation')?.value || document.getElementById('rd-stress')?.value || 5);
  const soreness = parseInt(document.getElementById('rd-soreness').value);
  const score = calculateReadiness(sleep, energy, motivation, soreness);
  const adj = getReadinessLoadAdjustment(score);
  // Stocker dans db.readiness (rétrocompat)
  db.readiness.push({ date: getTodayStr(), sleep, energy, motivation, soreness, score });
  // Stocker dans l'historique readiness (90 jours)
  if (!db.readinessHistory) db.readinessHistory = [];
  db.readinessHistory.push({ ts: Date.now(), sleep, energy, motivation, soreness, score });
  db.readinessHistory = db.readinessHistory.slice(-90);
  saveDB();
  // Stocker dans la séance active si elle existe
  if (activeWorkout) {
    activeWorkout.readiness = { sleep, energy, motivation, soreness, score, loadAdjustment: adj };
  }
  const modal = document.getElementById('readinessModal');
  if (modal) modal.remove();
  const adjMsg = adj === 1 ? '' : (adj > 1 ? ' (+' + Math.round((adj-1)*100) + '% charges)' : ' (' + Math.round((adj-1)*100) + '% charges)');
  showToast('✅ Readiness : ' + score + '/100' + adjMsg);
  if (_readinessOnComplete) { _readinessOnComplete(); _readinessOnComplete = null; }
}

function getReadinessBannerHtml() {
  const r = getTodayReadiness();
  if (!r) return '';
  var detail = '<div class="readiness-detail" style="display:none;margin-top:6px;font-size:11px;line-height:1.6;opacity:0.85;">' +
    '😴 Sommeil : ' + r.sleep + '/5 · ⚡ Énergie : ' + r.energy + '/5 · 💪 Courbatures : ' + r.soreness + '/5 · 🧠 Stress : ' + r.stress + '/5<br>' +
    'Score : (' + r.sleep + '+' + r.energy + '+' + r.soreness + '+' + r.stress + ') / 20 × 100 = ' + r.score + '/100' +
    '</div>';
  var toggleBtn = ' <span class="glossary-tip" onclick="event.stopPropagation();var d=this.parentElement.querySelector(\'.readiness-detail\');d.style.display=d.style.display===\'none\'?\'block\':\'none\';">ℹ️</span>';
  if (r.score < 40) return '<div style="background:rgba(255,69,58,0.15);border-left:3px solid var(--red);padding:8px 12px;margin:8px 0;border-radius:8px;font-size:12px;color:var(--red);">⚠️ Readiness faible (' + r.score + '/100) — séance allégée recommandée (volume -40%, charge -15%)' + toggleBtn + detail + '</div>';
  if (r.score < 60) return '<div style="background:rgba(255,159,10,0.12);border-left:3px solid var(--orange);padding:8px 12px;margin:8px 0;border-radius:8px;font-size:12px;color:var(--orange);">Readiness modérée (' + r.score + '/100) — charge maintenue, volume réduit (-1 set/exo)' + toggleBtn + detail + '</div>';
  if (r.score >= 80) return '<div style="background:rgba(50,215,75,0.12);border-left:3px solid var(--green);padding:8px 12px;margin:8px 0;border-radius:8px;font-size:12px;color:var(--green);">Readiness excellente (' + r.score + '/100) — go ! 💪' + toggleBtn + detail + '</div>';
  if (r.score >= 60) return '<div style="background:rgba(255,255,255,0.05);border-left:3px solid var(--sub);padding:8px 12px;margin:8px 0;border-radius:8px;font-size:12px;color:var(--text);">Readiness correcte (' + r.score + '/100) — programme normal' + toggleBtn + detail + '</div>';
  return '';
}

