    + '<button onclick="handleMagicChoice(\'import\')" '
    + 'style="width:100%;max-width:320px;padding:16px;margin-bottom:24px;'
    + 'border-radius:14px;background:var(--bg-card);color:var(--text);'
    + 'border:0.5px solid var(--border-card);'
