      escalade:'Escalade', velo:'Vélo', cyclisme:'Cyclisme', trail:'Trail',
      tennis:'Tennis', padel:'Padel', hyrox:'Hyrox', hiit:'HIIT',
      randonnee:'Randonnée', arts_martiaux:'Arts martiaux',
