function goRenderWizardStep() {
  var ws = window._wizState;
  var container = document.getElementById('goWizardContent');
  if (!container) return;
  var muscleList = ['Quadriceps','Ischio-jambiers','Fessiers','Pecs','Grand dorsal','Trapèzes','Épaules','Biceps','Triceps','Abdos (frontal)','Obliques','Lombaires','Mollets','Avant-bras'];
  var h = '';

  if (ws.step === 1) {
    h += '<div class="go-wizard-step active">';
    h += '<div class="go-wizard-title">Étape 1/3</div>';
    h += '<div class="go-wizard-sub">Informations de base</div>';
    h += '<div class="go-wizard-label">Nom de l\'exercice</div>';
    h += '<input type="text" id="wizName" value="' + ws.name.replace(/"/g, '&quot;') + '" placeholder="Ex: Curl araignée" style="margin-bottom:16px;">';
    h += '<div class="go-wizard-label">Matériel</div>';
    h += '<div class="go-wizard-grid">';
    var equipOpts = [{val:'barbell',icon:'🏋️',label:'Barre'},{val:'dumbbell',icon:'💪',label:'Haltères'},{val:'machine',icon:'⚙️',label:'Machine'},{val:'cable',icon:'🔗',label:'Câble'},{val:'bodyweight',icon:'🤸',label:'Corps'},{val:'other',icon:'📦',label:'Autre'}];
    equipOpts.forEach(function(o) {
      var sel = ws.equipment === o.val ? ' selected' : '';
      h += '<div class="go-wizard-opt' + sel + '" onclick="window._wizState.equipment=\'' + o.val + '\';goRenderWizardStep();"><div class="wiz-icon">' + o.icon + '</div>' + o.label + '</div>';
    });
    h += '</div>';
    h += '<div class="go-wizard-label">Type de comptage</div>';
    h += '<div class="go-wizard-grid col2">';
    var trackOpts = [{val:'weight',icon:'🏋️',label:'Poids × Réps'},{val:'reps',icon:'🔢',label:'Réps seules'},{val:'time',icon:'⏱',label:'Durée'},{val:'cardio',icon:'🏃',label:'Cardio'}];
    trackOpts.forEach(function(o) {
      var sel = ws.trackingType === o.val ? ' selected' : '';
      h += '<div class="go-wizard-opt' + sel + '" onclick="window._wizState.trackingType=\'' + o.val + '\';goRenderWizardStep();"><div class="wiz-icon">' + o.icon + '</div>' + o.label + '</div>';
    });
    h += '</div>';
    h += '<button class="go-wizard-next" onclick="goWizardNext()">Continuer →</button>';
    h += '</div>';
  } else if (ws.step === 2) {
    h += '<div class="go-wizard-step active">';
    h += '<div class="go-wizard-title">Étape 2/3</div>';
    h += '<div class="go-wizard-sub">Muscles ciblés</div>';
    h += '<div class="go-wizard-label">Muscle principal</div>';
    h += '<div class="go-wizard-muscles">';
    muscleList.forEach(function(m) {
      var sel = ws.primaryMuscle === m ? ' selected' : '';
      h += '<span class="go-wizard-muscle' + sel + '" onclick="window._wizState.primaryMuscle=\'' + m + '\';goRenderWizardStep();">' + m + '</span>';
    });
    h += '</div>';
    h += '<div class="go-wizard-label">Muscles secondaires</div>';
    h += '<div class="go-wizard-muscles">';
    muscleList.forEach(function(m) {
      if (m === ws.primaryMuscle) return;
      var sel = ws.secondaryMuscles.indexOf(m) >= 0 ? ' selected' : '';
      h += '<span class="go-wizard-muscle' + sel + '" onclick="goWizardToggleMuscle(\'secondaryMuscles\',\'' + m + '\')">' + m + '</span>';
    });
    h += '</div>';
    h += '<div class="go-wizard-label">Muscles tertiaires (stabilisateurs)</div>';
    h += '<div class="go-wizard-muscles">';
    muscleList.forEach(function(m) {
      if (m === ws.primaryMuscle || ws.secondaryMuscles.indexOf(m) >= 0) return;
      var sel = ws.tertiaryMuscles.indexOf(m) >= 0 ? ' selected' : '';
      h += '<span class="go-wizard-muscle' + sel + '" onclick="goWizardToggleMuscle(\'tertiaryMuscles\',\'' + m + '\')">' + m + '</span>';
    });
    h += '</div>';
    h += '<button class="go-wizard-next" onclick="goWizardNext()">Continuer →</button>';
    h += '</div>';
  } else if (ws.step === 3) {
    h += '<div class="go-wizard-step active">';
    h += '<div class="go-wizard-title">Étape 3/3</div>';
    h += '<div class="go-wizard-sub">Instructions d\'exécution</div>';
    h += '<textarea id="wizInstructions" rows="6" placeholder="1. Position de départ : pieds largeur d\'épaules...\n2. Descente : fléchir les genoux...\n3. Remontée : pousser sur les talons..." style="min-height:140px;font-size:14px;">' + ws.instructions + '</textarea>';
    h += '<button class="go-wizard-next" style="background:var(--green);" onclick="goWizardCreate()">✓ Créer l\'exercice</button>';
    h += '</div>';
  }

  container.innerHTML = h;
}

function goWizardNext() {
  var ws = window._wizState;
  if (ws.step === 1) {
    var nameInput = document.getElementById('wizName');
    ws.name = nameInput ? nameInput.value.trim() : '';
    if (!ws.name) { showToast('Donne un nom à l\'exercice'); return; }
    if (!ws.equipment) { showToast('Choisis un matériel'); return; }
    ws.step = 2;
  } else if (ws.step === 2) {
    if (!ws.primaryMuscle) { showToast('Choisis un muscle principal'); return; }
    ws.step = 3;
  }
  goRenderWizardStep();
}

function goWizardToggleMuscle(field, muscle) {
  var arr = window._wizState[field];
  var idx = arr.indexOf(muscle);
  if (idx >= 0) arr.splice(idx, 1);
  else arr.push(muscle);
  goRenderWizardStep();
}

function goWizardCreate() {
  var ws = window._wizState;
  var instrEl = document.getElementById('wizInstructions');
  ws.instructions = instrEl ? instrEl.value.trim() : '';

  var exo = {
    id: 'custom_' + generateId(),
    name: ws.name,
    nameAlt: [],
    equipment: ws.equipment,
    category: ws.trackingType === 'cardio' ? 'cardio' : 'compound',
    trackingType: ws.trackingType,
    primaryMuscles: [ws.primaryMuscle],
    secondaryMuscles: ws.secondaryMuscles.slice(),
    tertiaryMuscles: ws.tertiaryMuscles.slice(),
    defaultRest: ws.trackingType === 'cardio' ? 300 : 90,
    instructions: ws.instructions,
    createdAt: Date.now()
  };

  if (!db.customExercises) db.customExercises = [];
  db.customExercises.push(exo);
  _matchCacheInvalidate();
  _exoSearchIndex = null;
  saveDB();

  // Close wizard
  var el = document.getElementById('goWizardOverlay');
  if (el) el.remove();

  // Add to active workout if exists
  if (activeWorkout) {
    activeWorkout.exercises.push({
      exoId: exo.id,
      name: exo.name,
      sets: [],
      restSeconds: exo.defaultRest,
      notes: ''
    });
    goAutoSave();
    goRequestRender();
  }

  showToast('Exercice "' + exo.name + '" créé');
}

// ============================================================
// GO TAB — Muscle Distribution
// ============================================================
function renderGoMuscleDistribution() {
  if (!activeWorkout) return '';
  var muscleVolume = {};
  var muscleDetails = {}; // { parentGroup: { subMuscle: { sets, exercises:[] } } }

  activeWorkout.exercises.forEach(function(exo) {
    var completedSets = exo.sets.filter(function(s) { return s.completed; }).length;
    if (completedSets === 0) return;
    var contribs = getMuscleContributions(exo.name);
    contribs.forEach(function(c) {
      var parent = getMuscleGroupParent(c.muscle);
      var weighted = Math.round(completedSets * c.coeff * 2) / 2; // round to 0.5
      if (!muscleVolume[parent]) muscleVolume[parent] = 0;
      muscleVolume[parent] += weighted;
      if (!muscleDetails[parent]) muscleDetails[parent] = {};
      if (!muscleDetails[parent][c.muscle]) muscleDetails[parent][c.muscle] = { sets: 0, exercises: [], coeff: c.coeff };
      muscleDetails[parent][c.muscle].sets += weighted;
      if (muscleDetails[parent][c.muscle].exercises.indexOf(exo.name) < 0) {
        muscleDetails[parent][c.muscle].exercises.push(exo.name);
      }
    });
  });

  // Sort by volume
  var sorted = Object.keys(muscleVolume).sort(function(a, b) { return muscleVolume[b] - muscleVolume[a]; });
  if (sorted.length === 0) return '<div class="go-muscles-card"><div class="go-muscles-title">Répartition musculaire</div><div style="text-align:center;color:var(--sub);font-size:13px;padding:16px;">Valide des séries pour voir la répartition</div></div>';

  var maxVol = muscleVolume[sorted[0]] || 1;
  var colors = { 'Jambes':'var(--green)', 'Pecs':'var(--blue)', 'Dos':'var(--orange)', 'Épaules':'var(--purple)', 'Bras':'var(--teal)', 'Abdos':'var(--red)', 'Cardio':'var(--orange)' };

  var h = '<div class="go-muscles-card">';
  h += '<div class="go-muscles-title">Répartition musculaire</div>';

  sorted.forEach(function(group) {
    var vol = muscleVolume[group];
    var pct = Math.round((vol / maxVol) * 100);
    var color = colors[group] || 'var(--sub)';

    h += '<div class="go-muscle-row">';
    h += '<div class="go-muscle-dot" style="background:' + color + ';"></div>';
    h += '<div class="go-muscle-name">' + group + '</div>';
    h += '<div class="go-muscle-bar-bg"><div class="go-muscle-bar-fill" style="width:' + pct + '%;background:' + color + ';"></div></div>';
    h += '<div class="go-muscle-sets">' + vol + ' sér.</div>';
    h += '</div>';

    // Sub-muscles
    var subs = muscleDetails[group];
    if (subs) {
      h += '<div class="go-muscle-subs">';
      Object.keys(subs).forEach(function(sub) {
        var d = subs[sub];
        var coeffLabel = d.coeff >= 1 ? '1re' : d.coeff >= 0.5 ? '2nd' : '3re';
        var badgeClass = d.coeff >= 1 ? 'primary' : d.coeff >= 0.5 ? 'secondary' : 'tertiary';
        h += '<div class="go-muscle-sub-row">';
        h += '<span class="go-muscle-sub-badge ' + badgeClass + '">' + coeffLabel + '</span>';
        h += sub + ' · via ' + d.exercises.join(', ');
        h += '</div>';
      });
      h += '</div>';
    }
  });

  h += '</div>';
  return h;
}

// ============================================================
// GO TAB — Convert Workout & Finish
// ============================================================
function convertWorkoutToSession(workout) {
  var session = createSession(workout.title, workout.startTime);
  session.duration = Math.round((Date.now() - workout.startTime) / 1000);
  session.durationSource = 'go';

  // Group class: single cardio-like exercise with duration
  if (workout.isGroupClass) {
    session.isGroupClass = true;
    session.groupType = workout.groupType;
    var gExo = createExercise(workout.title);
    gExo.isCardio = true;
    gExo.exoType = 'cardio';
    gExo.maxTime = session.duration;
    gExo.cardioDate = workout.startTime;
    gExo.sets = 1;
    gExo.notes = workout.exercises[0] ? workout.exercises[0].notes : '';
    session.exercises.push(gExo);
    return finalizeSessionFromSeries(session);
  }

  workout.exercises.forEach(function(exo) {
    var exercise = createExercise(exo.name);
    var _bwData = exo.exoId ? EXO_DATABASE[exo.exoId] : null;
    var _hasBW = _bwData && _bwData.bwFactor && db.user.bw > 0;
    var _assist = exo.assistWeight || 0;
    var completedSets = exo.sets.filter(function(s) { return s.completed; });
    completedSets.forEach(function(s) {
      var w = s.weight || 0;
      // For BW exercises, store effective weight (body weight × factor + added - assist)
      if (_hasBW) {
        w = Math.round(db.user.bw * _bwData.bwFactor + (s.weight || 0) - _assist);
      }
      var _sType = s.type === 'warmup' ? 'warmup' : s.type === 'failure' ? 'failure' :
        s.type === 'drop' || s.type === 'dropset' ? 'dropset' :
        s.type === 'backoff' ? 'backoff' : 'normal';
      // Only push to series (used for e1RM/PR) if it's a real work set (not abandoned)
      if (_sType === 'normal' && !s.isAbandoned) {
        exercise.series.push({
          weight: w,
          reps: s.reps || (s.duration || 0),
          date: workout.startTime
        });
      }
      exercise.allSets.push({
        weight: w,
        reps: s.reps || (s.duration || 0),
        setType: _sType,
        rpe: s.rpe || null,
        grind: s.grind || false,
        grindTech: s.grindTech || false,
        isAbandoned: s.isAbandoned || false,
        hrAtLog:    s.hrAtLog    || null,
        hrPeak:     s.hrPeak     || null,
        hrRecov30:  s.hrRecov30  || null,
        hrRecov60:  s.hrRecov60  || null,
        hrAnalysis: s.hrAnalysis || null
      });
    });
    if (exercise.series.length > 0) session.exercises.push(exercise);
  });

  return finalizeSessionFromSeries(session);
}

function goConfirmFinish() {
  if (!activeWorkout) return;
  var totalExos = 0, totalSets = 0, tonnage = 0;
  activeWorkout.exercises.forEach(function(exo) {
    var done = exo.sets.filter(function(s) { return s.completed; });
    if (done.length > 0) totalExos++;
    totalSets += done.length;
    done.forEach(function(s) { tonnage += (s.weight || 0) * (s.reps || 0); });
  });
  var volStr = tonnage >= 1000 ? (tonnage / 1000).toFixed(1) + 't' : tonnage + 'kg';
  showModal(
    'Terminer la séance ?<br><span style="font-size:12px;color:var(--sub);">' + totalExos + ' exercices · ' + totalSets + ' séries · ' + volStr + ' de volume</span>',
    'Terminer',
    'var(--green)',
    function() { goFinishWorkout(); }
  );
}

function shouldRecordE1RMAsReference() {
  if (typeof isColdStart !== 'function' || !isColdStart()) return true;
  var wellbeing = db.todayWellbeing;
  if (!wellbeing) return true;
  var badSleep = wellbeing.sleep !== undefined && wellbeing.sleep <= 2;
  var badReadiness = wellbeing.readiness !== undefined && wellbeing.readiness <= 1;
  if (badSleep || badReadiness) {
    showToast('⚠️ État de santé insuffisant — cette séance ne sert pas de référence de calibration');
    return false;
  }
  return true;
}

var _ACTIVITY_EMOJI = {
  natation:'🏊', course:'🏃', velo:'🚴', yoga:'🧘',
  trail:'🥾', arts_martiaux:'🥊', randonnee:'🥾', ski:'⛷️',
  pilates:'🧘', sports_collectifs:'⚽', marche:'🚶', autre:'🏅'
};

function buildActivityQuickLogTags() {
  var template = (db.user && db.user.activityTemplate) || [];
  if (template.length === 0) return '';

  var today = new Date().getDay();
  var dayNames = ['Dimanche','Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi'];
  var todayName = dayNames[today];
  var todayStr = new Date().toISOString().split('T')[0];

  var todayActivities = template.filter(function(a) {
    return (a.days || []).includes(todayName);
  });
  if (todayActivities.length === 0) return '';

  var html = '<div style="margin-top:12px;padding-top:12px;'
    + 'border-top:1px solid rgba(255,255,255,0.08);">';
  html += '<div style="font-size:11px;color:var(--sub);margin-bottom:8px;">'
    + 'Cardio aujourd\'hui aussi ?</div>';
  html += '<div style="display:flex;gap:6px;flex-wrap:wrap;">';

  todayActivities.forEach(function(act, i) {
    var emoji = _ACTIVITY_EMOJI[act.type] || '🏅';
    var label = act.type.charAt(0).toUpperCase() + act.type.slice(1).replace(/_/g, ' ');
    // Check if already logged today
    var alreadyLogged = (db.activityLogs || []).some(function(l) {
      return l.date === todayStr && l.type === act.type;
    });
    var btnStyle = alreadyLogged
      ? 'background:rgba(50,215,75,0.2);border:1px solid var(--green);color:var(--green);'
      : 'background:var(--surface);border:1px solid var(--border);color:var(--sub);';
    html += '<button id="aqtag-' + i + '" onclick="logActivityTag(' + i + ', this)" '
      + 'style="padding:6px 12px;border-radius:20px;font-size:12px;cursor:pointer;'
      + 'transition:all 0.2s;' + btnStyle + '">'
      + emoji + ' ' + escapeHtml(label) + (alreadyLogged ? ' ✓' : '') + '</button>';
  });

  html += '</div></div>';
  return html;
}

function logActivityTag(templateIdx, btn) {
  var template = (db.user && db.user.activityTemplate) || [];
  var act = template[templateIdx];
  if (!act) return;

  var today = new Date().toISOString().split('T')[0];
  var trimp = typeof calcActivityTRIMP === 'function' ? calcActivityTRIMP(act) : 0;

  if (!db.activityLogs) db.activityLogs = [];
  var existingIdx = db.activityLogs.findIndex(function(l) {
    return l.date === today && l.type === act.type;
  });

  var log = { date: today, type: act.type, duration: act.duration || 45,
    intensity: act.intensity || 3, trimp: trimp, source: 'manual' };

  if (existingIdx >= 0) {
    db.activityLogs[existingIdx] = log;
  } else {
    db.activityLogs.push(log);
  }
  saveDB();

  btn.style.background = 'rgba(50,215,75,0.2)';
  btn.style.borderColor = 'var(--green)';
  btn.style.color = 'var(--green)';
  if (btn.textContent.indexOf('✓') === -1) btn.textContent = btn.textContent + ' ✓';
}

function showActivityQuickLog() {
  var template = (db.user && db.user.activityTemplate) || [];
  if (template.length === 0) return;

  var today = new Date().getDay();
  var dayNames = ['Dimanche','Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi'];
  var todayName = dayNames[today];

  var todayActivities = template.filter(function(a) {
    return (a.days || []).includes(todayName);
  });
  if (todayActivities.length === 0) return;

  var html = '<div style="padding:8px 0;">';
  html += '<div style="font-size:13px;color:var(--sub);margin-bottom:12px;">As-tu fait ces activités aujourd\'hui ?</div>';
  todayActivities.forEach(function(act, i) {
    var trimp = typeof calcActivityTRIMP === 'function' ? calcActivityTRIMP(act) : 0;
    var label = act.type.charAt(0).toUpperCase() + act.type.slice(1).replace(/_/g, ' ');
    html += '<div id="aq-item-' + i + '" onclick="logActivityFromQuickLog(' + i + ')" '
      + 'style="display:flex;justify-content:space-between;align-items:center;'
      + 'padding:10px 12px;border-radius:10px;margin-bottom:8px;cursor:pointer;'
      + 'background:var(--surface);border:1px solid var(--border);">';
    html += '<div>';
    html += '<div style="font-size:13px;font-weight:600;">' + escapeHtml(label) + '</div>';
    html += '<div style="font-size:11px;color:var(--sub);">' + (act.duration || 45) + ' min · ' + labelFor('trimp','TRIMP') + ' ' + trimp + '</div>';
    html += '</div>';
    html += '<div id="aq-check-' + i + '" style="font-size:20px;">⬜</div>';
    html += '</div>';
  });
  html += '</div>';

  showInfoModal('Activités du jour', html);
}

function logActivityFromQuickLog(templateIdx) {
  var template = (db.user && db.user.activityTemplate) || [];
  var act = template[templateIdx];
  if (!act) return;

  var today = new Date().toISOString().split('T')[0];
  var trimp = typeof calcActivityTRIMP === 'function' ? calcActivityTRIMP(act) : 0;

  if (!db.activityLogs) db.activityLogs = [];

  var existingIdx = db.activityLogs.findIndex(function(l) {
    return l.date === today && l.type === act.type;
  });

  var log = {
    date: today,
    type: act.type,
    duration: act.duration || 45,
    intensity: act.intensity || 3,
    trimp: trimp,
    source: 'manual'
  };

  if (existingIdx >= 0) {
    db.activityLogs[existingIdx] = log;
  } else {
    db.activityLogs.push(log);
  }
  saveDB();

  var checkEl = document.getElementById('aq-check-' + templateIdx);
  var itemEl = document.getElementById('aq-item-' + templateIdx);
  if (checkEl) checkEl.textContent = '✅';
  if (itemEl) itemEl.style.borderColor = 'var(--green)';

  showToast('✅ ' + (log.type.charAt(0).toUpperCase() + log.type.slice(1).replace(/_/g, ' ')) + ' enregistrée');
}

function goFinishWorkout() {
  if (!activeWorkout) return;
  var session = convertWorkoutToSession(activeWorkout);

  // Aggregate per-set HR data into session summary
  try {
    var _allHR = [];
    activeWorkout.exercises.forEach(function(e) {
      (e.sets || []).forEach(function(s) {
        if (s.hrPeak) _allHR.push(s.hrPeak);
      });
    });
    session.hrData = _allHR.length > 0 ? {
      mean:    Math.round(_allHR.reduce(function(a,b){return a+b;},0) / _allHR.length),
      peak:    Math.max.apply(null, _allHR),
      samples: _allHR.length
    } : null;
  } catch(e) { session.hrData = null; }

  // Track old PRs for PR detection
  const oldPRs = { bench: db.bestPR.bench, squat: db.bestPR.squat, deadlift: db.bestPR.deadlift };
  // Snapshot des meilleurs e1RM par exo AVANT d'ajouter la séance (pour overlay PR Type B)
  var _previousBestE1RMs = {};
  try { _previousBestE1RMs = typeof getAllBestE1RMs === 'function' ? getAllBestE1RMs() : {}; } catch(e) {}

  // Cold start reference guard: flag if health state is too poor to serve as calibration
  if (!shouldRecordE1RMAsReference()) {
    session.skipColdStartRef = true;
  }

  // Add to db.logs
  db.logs.push(session);
  try { updateActiveProgramStats(); } catch(e) {}
  saveDBNow();
  if (!navigator.onLine) {
    showToast('📱 Séance sauvegardée localement — sync au retour du réseau');
  }

  // Generate AI debrief
  try { saveAlgoDebrief(session); } catch(e) {}

  // Wisdom badges (Gemini v207)
  try { checkWisdomBadge_Recovery(); } catch(e) {}
  try { checkWisdomBadge_ACWR(); } catch(e) {}

  // Social: publish session activity
  try { publishSessionActivity(session); } catch(e) {}

  // Social: detect new PRs and publish + celebration
  try {
    recalcBestPR();
    if (typeof calcAndStoreLiftRanks === 'function') calcAndStoreLiftRanks();
    if (typeof calcAndStoreMuscleRanks === 'function') calcAndStoreMuscleRanks(true);
    SBD_TYPES.forEach(type => {
      if (db.bestPR[type] > oldPRs[type] && oldPRs[type] > 0) {
        const name = type === 'bench' ? 'Développé couché' : type === 'squat' ? 'Squat' : 'Soulevé de terre';
        publishPRActivity(name, db.bestPR[type], oldPRs[type]);
        sendLocalNotification('🏆 Nouveau record !', name + ' : ' + db.bestPR[type] + 'kg (ancien: ' + oldPRs[type] + 'kg)');
      }
    });
    // Overlay PR Type B — un seul par séance, sur le premier SBD exo qui bat le précédent e1RM
    var _prCelebrated = false;
    (session.exercises || []).forEach(function(_exo) {
      if (_prCelebrated) return;
      var _sbd = typeof getSBDType === 'function' ? getSBDType(_exo.name) : null;
      if (!_sbd) return;
      var _prev = (_previousBestE1RMs[_exo.name] && _previousBestE1RMs[_exo.name].e1rm) || 0;
      if (!(_exo.maxRM > _prev && _prev > 0)) return;
      // Anti-doublon : même (exo, poids arrondi) dans les 24h
      db.gamification = db.gamification || {};
      db.gamification.lastPRCelebrated = db.gamification.lastPRCelebrated || {};
      var _key = _exo.name + '_' + Math.round(_exo.maxRM);
      if (db.gamification.lastPRCelebrated[_key]
          && Date.now() - db.gamification.lastPRCelebrated[_key] < 86400000) return;
      db.gamification.lastPRCelebrated[_key] = Date.now();
      var _newTierName = null;
      if (db.gamification.liftRanks && db.gamification.liftRanks[_sbd]) {
        _newTierName = db.gamification.liftRanks[_sbd].tier;
      }
      if (typeof showPROverlay === 'function') showPROverlay(_exo.name, Math.round(_exo.maxRM), _newTierName);
      _prCelebrated = true;
    });
    updateLeaderboardSnapshot();
  } catch(e) {}

  // LP 3-Strikes: detect failures (RPE ≥ 9.5 on last work set = missed reps)
  try {
    if (typeof isInLP === 'function' && isInLP()) {
      (session.exercises || []).forEach(function(_lpExo) {
        var _lpWork = (_lpExo.allSets || _lpExo.series || []).filter(function(s) {
          return !s.isWarmup && !s.isBackOff;
        });
        if (!_lpWork.length) return;
        var _lpLastSet = _lpWork[_lpWork.length - 1];
        if (parseFloat(_lpLastSet.rpe) >= 9.5) {
          var _lpRes = typeof recordLPFailure === 'function'
            ? recordLPFailure(_lpExo.name, parseFloat(_lpLastSet.weight) || 0)
            : null;
          if (_lpRes && _lpRes.message) showToast(_lpRes.message);
        }
      });
    }
  } catch(e) {}

  // Mise à jour EWMA après chaque séance loggée
  try {
    if (typeof updateEWMAForExo === 'function') {
      var _isDeload = typeof isDeloadWeek === 'function' && isDeloadWeek();
      (session.exercises || []).forEach(function(_ewmaExo) {
        if (!_ewmaExo.name || !_ewmaExo.maxRM || _ewmaExo.maxRM <= 0) return;
        updateEWMAForExo(_ewmaExo.name, _ewmaExo.maxRM, _isDeload);
      });
      saveDB();
    }
  } catch(e) {}

  // Cleanup
  try { localStorage.removeItem('SBD_ACTIVE_WORKOUT'); } catch(e) {}
  clearWorkoutIDB();
  goStopAutoSave();
  goStopSessionTimer();
  goSkipRest();
  goReleaseWakeLock();
  if (_goPipVisibilityHandler) { document.removeEventListener('visibilitychange', _goPipVisibilityHandler); _goPipVisibilityHandler = null; }
  if (document.pictureInPictureElement) { try { document.exitPictureInPicture(); } catch(e) {} }

  activeWorkout = null;
  _goSessionPaused = false;
  db._expressMode = false;

  // Notification
  var _nSets = 0, _nTonnage = 0;
  (session.exercises||[]).forEach(function(e) { _nSets += (e.sets||0); });
  _nTonnage = session.volume || 0;
  var _sessionNotifTitle = '✅ Séance terminée';
  var _sessionNotifBody = 'Bravo ! ' + _nSets + ' séries, ' + (_nTonnage >= 1000 ? (_nTonnage/1000).toFixed(1) + 't' : _nTonnage + 'kg') + ' de volume';
  sendLocalNotification(_sessionNotifTitle, _sessionNotifBody);
  addToNotificationHistory(_sessionNotifTitle, _sessionNotifBody, 'session_complete');
  sendPushNotification(_sessionNotifTitle, _sessionNotifBody, 'session_complete');

  checkAndShowPRCelebration(session);

  // Award any newly unlocked badges (permanent store)
  try { checkAndAwardBadges(); } catch(e) {}

  // Mettre à jour le snapshot articulaire après chaque séance
  if (typeof calcCurrentJointStress === 'function') {
    try { db.user.jointHealth = calcCurrentJointStress(); } catch(e) {}
  }

  // Proposer le partage si PR ou tonnage > 2t
  try {
    var _shareCard = typeof generateShareCard === 'function' ? generateShareCard(session) : null;
    if (_shareCard && (_shareCard.hasPR || _shareCard.tonnage > 2)) {
      var _lastSession = session;
      setTimeout(function() {
        var t = document.createElement('div');
        t.className = 'toast';
        t.style.cssText = 'cursor:pointer;text-decoration:underline;';
        t.textContent = '📸 Partager ta séance';
        t.onclick = function() { showShareModal(_lastSession); t.remove(); };
        document.body.appendChild(t);
        setTimeout(function() { t.remove(); }, 5000);
      }, 3500);
    }
  } catch(e) {}

  showToast('✅ Séance sauvegardée');
  renderGoTab();

  // Naviguer vers la semaine de la séance dans Training
  try {
    var _sesTs = session.timestamp;
    var _thisWeekStart = getWeekStart(Date.now());
    var _sesWeekStart = getWeekStart(_sesTs);
    var _weekDiff = Math.round((_sesWeekStart - _thisWeekStart) / (7 * 86400000));
    currentWeekOffset = _weekDiff;
    // Forcer le re-render si l'onglet séances est visible
    if (activeSeancesSub === 's-log') {
      renderSeancesTab();
    }
  } catch(e) {}

  // Force render all key views — refreshUI() only renders the active sub-tab
  // which is still 's-go' at this point
  if (activeSeancesSub !== 's-log') {
    renderSeancesTab();
  }
  renderDash();

  // Social: clear training status
  try { setTrainingStatus(false); } catch(e) {}

  // Proposer d'ajouter des photos après la séance
  setTimeout(function() {
    showModal(
      '📷 Ajouter des photos ?<br><span style="font-size:12px;color:var(--sub);">Tu peux ajouter 1 à 4 photos à cette séance.</span>',
      'Ajouter des photos',
      'var(--accent)',
      function() { openSessionPhotoPicker(session.id); },
      'Plus tard'
    );
  }, 1500);
}

// ── Feature 3: PR Celebration (Gemini Q4.1) ────────────────────────────────

// ── WAITLIST ──────────────────────────────────────────────────
function checkWaitlistRoute() {
  if (window.location.hash === '#waitlist'
      || (window.location.search && window.location.search.includes('waitlist'))) {
    var wl = document.getElementById('waitlist-page');
    var app = document.getElementById('app-shell') || document.querySelector('.app-container');
    if (wl) wl.style.display = 'block';
    if (app) app.style.display = 'none';
    // Also hide top-level sections that may be visible
    ['tab-dash','tab-seances','tab-stats','tab-social','tab-profil','tab-ai','tab-game',
     'tab-nav','bottom-nav'].forEach(function(id) {
      var el = document.getElementById(id);
      if (el) el.style.display = 'none';
    });
    return true;
  }
  return false;
}

async function submitWaitlist() {
  var emailEl = document.getElementById('wl-email');
  var profileEl = document.getElementById('wl-profile');
  var email = emailEl ? emailEl.value.trim() : '';
  var profile = profileEl ? profileEl.value : '';

  if (!email || !email.includes('@') || !email.includes('.')) {
    showToast('⚠️ Email invalide');
    return;
  }

  var btn = document.querySelector('[onclick="submitWaitlist()"]');
  if (btn) { btn.disabled = true; btn.textContent = 'Envoi…'; }

  try {
    if (typeof supaClient !== 'undefined' && supaClient) {
      var res = await supaClient.from('waitlist').insert({
        email: email, profile: profile || null,
        created_at: new Date().toISOString()
      });
      if (res.error && res.error.code !== '23505') throw res.error;
    }

    if (emailEl) emailEl.style.display = 'none';
    if (profileEl) profileEl.style.display = 'none';
    if (btn) {
      btn.disabled = false;
      btn.innerHTML = '✅ Tu es sur la liste !<br><span style="font-size:12px;font-weight:400;">'
        + 'On te contacte en septembre.</span>';
      btn.style.background = 'var(--green,#32D74B)';
    }
    var counter = document.getElementById('wl-count');
    if (counter) {
      var cur = parseInt(counter.textContent) || 50;
      counter.textContent = (cur + 1) + '+';
    }
  } catch(e) {
    if (btn) { btn.disabled = false; btn.textContent = 'Rejoindre la liste d\'attente →'; }
    showToast('❌ Erreur, réessaie dans un moment');
  }
}

function renderShareCardHTML(cardData) {
  if (!cardData) return '';
  var hasPR = cardData.hasPR;
  var bg = hasPR
    ? 'linear-gradient(135deg,#1a1a2e 0%,#16213e 50%,#0f3460 100%)'
    : 'linear-gradient(135deg,#0C0C18 0%,#1a1a2e 100%)';
  var accent = hasPR ? '#FFD700' : '#0A84FF';

  var html = '<div id="share-card" style="'
    + 'width:340px;min-height:440px;background:' + bg + ';'
    + 'border-radius:20px;padding:24px;'
    + 'font-family:-apple-system,BlinkMacSystemFont,sans-serif;'
    + 'color:#fff;position:relative;overflow:hidden;">';

  if (hasPR) {
    html += '<div style="position:absolute;top:16px;right:16px;'
      + 'background:' + accent + ';color:#000;padding:3px 10px;'
      + 'border-radius:20px;font-size:10px;font-weight:800;letter-spacing:1px;">🏆 PR</div>';
  }

  html += '<div style="display:flex;align-items:center;gap:6px;margin-bottom:18px;">';
  html += '<div style="font-size:18px;font-weight:900;color:' + accent + ';">TrainHub</div>';
  html += '<div style="font-size:10px;color:rgba(255,255,255,0.35);margin-top:2px;">by SBD</div>';
  html += '</div>';

  html += '<div style="margin-bottom:16px;">';
  html += '<div style="font-size:20px;font-weight:800;margin-bottom:3px;">'
    + escapeHtml(cardData.userName) + '</div>';
  html += '<div style="font-size:12px;color:rgba(255,255,255,0.45);">' + cardData.date;
  if (cardData.phase) {
    html += ' · Phase ' + cardData.phase.charAt(0).toUpperCase() + cardData.phase.slice(1);
  }
  html += '</div></div>';

  if (cardData.prs.length > 0) {
    html += '<div style="margin-bottom:16px;">';
    cardData.prs.forEach(function(pr) {
      html += '<div style="background:rgba(255,215,0,0.1);border:1px solid rgba(255,215,0,0.3);'
        + 'border-radius:10px;padding:10px 12px;margin-bottom:6px;'
        + 'display:flex;justify-content:space-between;align-items:center;">';
      html += '<div style="font-size:12px;color:rgba(255,255,255,0.75);">' + escapeHtml(pr.name) + '</div>';
      html += '<div style="font-size:18px;font-weight:800;color:#FFD700;">' + pr.value + 'kg</div>';
      html += '</div>';
    });
    html += '</div>';
  }

  if (cardData.mainLifts.length > 0) {
    html += '<div style="margin-bottom:16px;">';
    cardData.mainLifts.forEach(function(lift) {
      html += '<div style="display:flex;justify-content:space-between;align-items:center;'
        + 'padding:7px 0;border-bottom:1px solid rgba(255,255,255,0.06);">';
      html += '<div style="font-size:12px;color:rgba(255,255,255,0.55);">' + escapeHtml(lift.name) + '</div>';
      html += '<div style="font-size:13px;font-weight:700;">' + lift.weight + 'kg × ' + lift.reps;
      if (lift.rpe) html += ' <span style="color:rgba(255,255,255,0.35);font-size:10px;">@' + lift.rpe + '</span>';
      html += '</div></div>';
    });
    html += '</div>';
  }

  html += '<div style="padding-top:14px;border-top:1px solid rgba(255,255,255,0.1);'
    + 'display:flex;justify-content:space-between;align-items:center;">';
  html += '<div>';
  html += '<div style="font-size:10px;color:rgba(255,255,255,0.35);">TONNAGE</div>';
  html += '<div style="font-size:20px;font-weight:800;color:' + accent + ';">' + cardData.tonnage + 't</div>';
  html += '</div>';
  html += '<div style="font-size:9px;color:rgba(255,255,255,0.2);text-align:right;">trainhub.app</div>';
  html += '</div>';
  html += '</div>';
  return html;
}

function showShareModal(session) {
  var cardData = typeof generateShareCard === 'function' ? generateShareCard(session) : null;
  if (!cardData) return;
  var o = document.createElement('div');
  o.className = 'modal-overlay';
  o.onclick = function(e) { if (e.target === o) o.remove(); };
  o.innerHTML = '<div class="modal-box" style="max-width:380px;">'
    + '<div style="font-size:14px;font-weight:700;margin-bottom:12px;">📸 Partager ta séance</div>'
    + renderShareCardHTML(cardData)
    + '<div style="display:flex;gap:8px;margin-top:14px;">'
    + '<button onclick="downloadShareCard()" style="flex:1;padding:12px;background:var(--accent);border:none;'
    + 'border-radius:12px;color:#fff;font-weight:700;font-size:13px;cursor:pointer;">📥 Télécharger</button>'
    + '<button onclick="this.closest(\'.modal-overlay\').remove()" style="flex:1;padding:12px;'
    + 'background:var(--surface);border:1px solid var(--border);border-radius:12px;'
    + 'color:var(--text);font-size:13px;cursor:pointer;">Fermer</button>'
    + '</div></div>';
  document.body.appendChild(o);
}

async function downloadShareCard() {
  var card = document.getElementById('share-card');
  if (!card) return;
  try {
    if (typeof html2canvas === 'undefined') {
      var script = document.createElement('script');
      script.src = 'https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js';
      document.head.appendChild(script);
      await new Promise(function(res) { script.onload = res; });
    }
    var canvas = await html2canvas(card, { backgroundColor: null, scale: 2, useCORS: true });
    var link = document.createElement('a');
    link.download = 'trainhub-' + new Date().toISOString().split('T')[0] + '.png';
    link.href = canvas.toDataURL('image/png');
    link.click();
    showToast('✅ Carte téléchargée !');
  } catch(e) {
    showToast('⚠️ Téléchargement indisponible');
  }
}

function checkAndShowPRCelebration(session) {
  if (!session || !session.exercises) return;
  var prevLogs = (db.logs || []).filter(function(l) { return l.id !== session.id; });
  if (prevLogs.length === 0) return;

  var newPRs = [];
  (session.exercises || []).forEach(function(exo) {
    if (!exo.maxRM || exo.isSubstituted) return;
    var prevBest = 0;
    prevLogs.forEach(function(ol) {
      (ol.exercises || []).forEach(function(oe) {
        if (oe.name === exo.name && (oe.maxRM || 0) > prevBest) prevBest = oe.maxRM || 0;
      });
    });
    if (exo.maxRM > prevBest && prevBest > 0) {
      newPRs.push({
        name: exo.name,
        value: Math.round(exo.maxRM),
        prev: Math.round(prevBest),
        gain: Math.round(exo.maxRM - prevBest)
      });
    }
  });

  if (newPRs.length === 0) {
    // No PR but show activity tags if relevant
    setTimeout(function() {
      var tags = typeof buildActivityQuickLogTags === 'function' ? buildActivityQuickLogTags() : '';
      if (!tags) return;
      var html = '<div style="text-align:center;padding:8px 0 4px;">';
      html += '<div style="font-size:32px;margin-bottom:6px;">✅</div>';
      html += '<div style="font-size:16px;font-weight:700;margin-bottom:12px;">Séance enregistrée</div>';
      html += tags;
      html += '<button onclick="closeModal()" style="width:100%;margin-top:14px;padding:11px;'
        + 'background:var(--surface);border:1px solid var(--border);border-radius:12px;'
        + 'color:var(--text);font-size:13px;cursor:pointer;">Fermer</button>';
      html += '</div>';
      showModal('', html);
    }, 600);
    return;
  }
  setTimeout(function() { showPRCelebration(newPRs, session.id); }, 600);
}

function showPRCelebration(prs, sessionId) {
  var html = '<div style="text-align:center;padding:16px 0;">';
  html += '<div style="font-size:48px;margin-bottom:8px;">🏆</div>';
  html += '<div style="font-size:20px;font-weight:800;margin-bottom:4px;">Nouveau Record !</div>';
  html += '<div style="font-size:13px;color:var(--sub);margin-bottom:20px;">Tu viens de repousser tes limites</div>';

  prs.forEach(function(pr) {
    html += '<div style="background:rgba(50,215,75,0.1);border:1px solid rgba(50,215,75,0.3);'
      + 'border-radius:14px;padding:14px;margin-bottom:10px;">';
    html += '<div style="font-size:13px;color:var(--sub);margin-bottom:4px;">' + escapeHtml(pr.name) + '</div>';
    html += '<div style="font-size:28px;font-weight:800;color:var(--green);">' + pr.value + 'kg</div>';
    html += '<div style="font-size:12px;color:var(--sub);">Précédent : ' + pr.prev + 'kg · Gain : +' + pr.gain + 'kg</div>';
    html += '</div>';
  });

  // One-tap activity tags (non-blocking)
  html += buildActivityQuickLogTags();

  html += '<div style="display:flex;gap:8px;margin-top:16px;">';
  html += '<button onclick="closeModal()" '
    + 'style="flex:1;padding:12px;background:var(--surface);border:1px solid var(--border);'
    + 'border-radius:12px;color:var(--text);font-size:13px;cursor:pointer;">Fermer</button>';
  html += '<button onclick="closeModal();if(typeof shareSessionToFeed===\'function\')shareSessionToFeed(\'' + (sessionId || '') + '\')" '
    + 'style="flex:1;padding:12px;background:var(--green);border:none;'
    + 'border-radius:12px;color:#fff;font-weight:700;font-size:13px;cursor:pointer;">📤 Partager</button>';
  html += '</div></div>';

  showModal('', html);

  sendLocalNotification('Nouveau PR 🏆', prs.map(function(p) {
    return p.name + ' : ' + p.value + 'kg (+' + p.gain + 'kg)';
  }).join(', '));
}

function goConfirmDiscard() {
  showModal(
    'Annuler la séance ?<br><span style="font-size:12px;color:var(--sub);">Toutes les données de cette séance seront perdues.</span>',
    'Annuler la séance',
    'var(--red)',
    function() { goDiscardWorkout(); }
  );
}

function goDiscardWorkout() {
  try { localStorage.removeItem('SBD_ACTIVE_WORKOUT'); } catch(e) {}
  goStopAutoSave();
  goStopSessionTimer();
  goSkipRest();
  goReleaseWakeLock();
  if (_goPipVisibilityHandler) { document.removeEventListener('visibilitychange', _goPipVisibilityHandler); _goPipVisibilityHandler = null; }
  if (document.pictureInPictureElement) { try { document.exitPictureInPicture(); } catch(e) {} }
  activeWorkout = null;
  _goSessionPaused = false;
  showToast('Séance annulée');
  renderGoTab();

  // Social: clear training status
  try { setTrainingStatus(false); } catch(e) {}
}

